import{_ as e,o as l,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung045.jpg",m=JSON.parse('{"title":"Übung Lektion 28","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung28.md","filePath":"lektionen/uebung28.md"}'),a={name:"lektionen/uebung28.md"};function s(d,i,u,o,p,h){return l(),n("div",null,[...i[0]||(i[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-28" tabindex="-1">Übung Lektion 28 <a class="header-anchor" href="#ubung-lektion-28" aria-label="Permalink to &quot;Übung Lektion 28&quot;">​</a></h1><p>A) Bilden Sie das Kausativum zu folgenden Verbformen und Partizipialformen und geben Sie die Bedeutung an:</p><p>1. Mit hochstufiger Wurzel:</p><ol><li>अर्हन्ति अर्हयन्ति</li><li>प्राप्य प्राप्य</li><li>एषिष्यन्ति एषयिष्यन्ति</li><li>कुप्यति कोपयति</li><li>कर्क्ष्यति कर्षयिष्यति</li><li>क्रुध्यन्ती क्रोधयन्ती</li><li>चोर्य्यते चोर्यते</li><li>गन्तुम् गमयितुम्</li><li>जातः जनितः</li><li>देक्ष्यन्ति देशयिष्यन्ति</li><li>दोग्धि दोहयति</li><li>माद्यन् मदयन्</li><li>द्रक्ष्यति दर्शयिष्यति</li><li>द्वेष्टि द्वेषयति</li><li>नर्तितुम् नर्तयितुम्</li><li>भोत्स्यन्ते बोधयिष्यन्ते</li><li>मुञ्चन्ति मोचयन्ति</li><li>पृच्छन्ति प्रच्छयन्ति</li><li>मुह्यति मोहयति</li><li>योत्स्यन् योधयिष्यन्</li><li>रक्ष्यते रक्ष्यते</li><li>रोदिति रोदयति</li><li>लुब्धा लोभिता</li><li>प्रविश्य प्रवेश्य</li><li>वर्तते वर्तयते</li><li>सिक्त्वा सेचयित्वा</li><li>स्रक्ष्यति सर्जयिष्यति</li><li>लिम्पन्ति लेपयन्ति</li><li>वृद्धाः वर्धिताः</li></ol><p>2. Mit dehnstufiger Wurzel:</p><ol><li>अत्ति आदयति</li><li>अस्यन्ति आसयन्ति</li><li>एष्यति आययिष्यति</li><li>संस्कृतम् संस्कारितम्</li><li>चरति चारयति</li><li>तनोति तानयति</li><li>खाद्यते खाद्यते</li><li>धक्ष्यति दाहयिष्यति</li><li>उप</li><li>उपानेष्यति उपानायिष्यति</li><li>पच्यते पाच्यते</li><li>पतन्ति पातयन्ति</li><li>पत्स्यते पादयिष्यते</li><li>भक्तः भाजितः</li><li>भवति भावयति</li><li>मंस्यन्ते मानयिष्यन्ते</li><li>म्रियते मारयति । मार्यते</li><li>इज्यते याज्यते</li><li>वक्ति वाचयति</li><li>प्रोद्य प्रवाद्य</li><li>शृणोति श्रावयति</li><li>सुन्वन्ति सावयति</li><li>स्तौति स्तावयति</li><li>विस्मृत्य विस्मार्य</li><li>उषितः वासितः</li><li>वसिता वासिता</li><li>अश्नुते आशयति</li><li>आसते आसयन्ते</li><li>त्यक्ष्यता त्याजयिष्यता</li><li>धृतेन धारितेन</li><li>म्रियन्ते मारयन्ति । मार्यन्ते</li><li>यजतः याजयतः</li><li>उक्ते वाचिते</li><li>उद्यन्ते वाद्यन्ते</li><li>शक्नुवन्ति शाकयन्ति</li><li>श्रोष्यन्तः श्रावयिष्यन्तः</li><li>सीदति सादयति</li><li>सोढायाः साहितायाः</li><li>हरन्ती हरयन्ती</li><li>ऊढया वाहितया</li></ol><p>3. Kausativ auf -पय</p><ol><li>स्थित्वा स्थापयित्वा</li></ol><p>4. Beachten und lernen Sie besonders folgende Kausativbildungen</p><ol><li>दुष् दूषयति</li><li>पा 1 (&quot;trinken2) पाययति (aus: pai-aya-ti)</li><li>पा 2 (&quot;schützen&quot;) पालयति</li><li>लभ् लम्भयति</li><li>हन् घातयति</li><li>जि जापयति</li><li>जीव् जीवयति</li></ol><p>B. Übersetzen Sie folgende Sätze, lösen Sie die Komposita in Sanskrit auf und bilden Sie mittels der einfachen Verben Sätze, die ausdrücken, was geschieht, wenn das durch das Kausativum ausgedrückte bewirkt wird:</p><p>Beispiel: रामो दासं भारं हारयति » दासो भारं हरति</p><p>शत्रुजयाय क्षत्रियो ब्राह्मणेन हरिहरं याजयित्वारीन्योत्स्यते ॥१॥ शत्रूणां जयाय । हरिं च हरं च । Der Kṣatriya hat, um die Feinde zu besiegen, einen Brahmanen Hari und Hara mit einem Opfer verehren lassen und wird die Feinde bekämpfen. ब्राह्मणि हरहरिं यजति ।</p><p>गुरुर्बालान्वेदमध्याप्य गृहं गतः ॥२॥ Der Lehrer hat den Knaben den Veda gelehrt und ist dann nach Hause gegangen. बाला वेदमधीयते ।</p><p>गर्भगृहे देवीप्रतिमा दर्श्यते ॥३॥ Im innersten Heiligtum wird das Bildnis der Göttin gezeigt. देवीप्रतिमा दृश्यते ।</p><p>यजन्नग्निनान्नमादयति पानं च पाययति ॥४॥ Der Opfernde gibt dem Feuer Speise zu essen und Trank zu trinken. अग्निरन्नमत्ति पानं च पिबति ।</p><p>पुत्रे जाते ब्राह्मणी दासं ब्राह्मनं गमयति । ब्राह्मणस्तं दासं गृहं प्रवेश्य पुत्रं पृच्छति । सुभगः पुत्र इति दासो वक्ति । तच्छ्रुत्वा ब्राह्मणो सुखतां गच्छति ॥५॥ शोभनो भगो यस्य सः । Sobald der Sohn geboren ist, schickt die Brahmanin einen Diener zum Brahmanen. Der Brahmane lässt den Diener ins Haus kommen und fragt nach seinem Sohn. Der Diener sagt, dass der Sohn wohlauf ist. Als er das hört wird der Brahmane glücklich. दासो ब्राह्मणं गच्छति । दासो गृहं प्रविशति ।</p><p>स्तुवता नरेण देवा महाकवेः स्तोत्राणि श्राविताः ॥६॥ मह्तेः कवेः । Der lobsingende Mann bringt den Göttern die Lobeshymnen des großen Dichters zu Gehör. देवा महाकवेः स्तोत्राणि शृण्वन्ति ।</p><p>आर्ययोधैर्महायुद्धे ऽरयो मार्यन्ते ॥७॥ आर्यैर्योधैः । महति युद्धे । Die edlen Krieger töten in der großen Schlacht die Feinde. अरयो म्रियन्ते ।</p><p>सत्क्षत्रिया ब्राह्मणेनेष्टदेवतापूजां कारयति । स ब्राह्मणः पूजां कृत्वा क्षत्रियाया धनमेषिष्यति ॥८॥ सती क्त्रिया । इष्टाया देवतायाः पूजां ।  Die gute Kṣatriyā lässt einen Brahmanen ihre persönliche Gottheit verehren. Wenn er die Verehrungszeremonie vollzogen hat, wird der Brahmanin von der Kṣatriyā Geld wünschen. ब्राह्मण इष्टदेवतापूजां करोति ।</p><p>धनं जेतुं महाक्षत्रियो योधव्याघ्रैर्व्रतानि चारयिष्यति ॥९॥ महान्क्षत्रियः । व्याघ्रैरिव योधैः । Um Reichtümer zu erobern, wird der große Kṣatriya die tigergleichen Kämpfer Gelübde halten lassen. योधव्याघ्रा व्रतानि चरिष्यन्ति ।</p><p>पापाद्मोक्षार्थेन सुगत आर्यजनानार्यसत्यानि बोधयति ॥१०॥ मोक्षस्यार्थेन । सूष्टु गतः । आर्यान्जनान् । आर्याणि सत्यानि । Um sie vom Übel zu befreien, lässt Buddha edle Menschen die edlen Wahrheiten erkennen. आर्यजना आर्यसत्यानि बुध्यन्ते ।</p><p><img src="'+t+'" alt=""><br> Abb.: गर्भगृहे देवीप्रतिमा दर्श्यते<br> Birla Mandir Jaipur = बिर्ला मन्दिर, जयपुर<br> [Bildquelle: digitaura. -- <a href="http://www.flickr.com/photos/digitaura/262342685/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/digitaura/262342685/</a>. -- Zugriff am 2008-12-29. --  <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',24)])])}const c=e(a,[["render",s]]);export{m as __pageData,c as default};
